use criterion::{criterion_group, criterion_main, Criterion};
use stats_models::Lm;

fn benchmark_lm_fit(c: &mut Criterion) {
    // Generate identity matrix data as flattened vec
    let n_obs = 100;
    let n_vars = 100;
    let mut x_data = vec![0.0; n_obs * n_vars];

    // Create identity matrix
    for i in 0..n_obs {
        for j in 0..n_vars {
            if i == j {
                x_data[i * n_vars + j] = 1.0;
            }
        }
    }

    let y = vec![1.0; n_obs];

    c.bench_function("lm_fit_100x100", |b| {
        b.iter(|| {
            let _fit = Lm::fit(&x_data, &y, n_obs, n_vars).unwrap();
        })
    });
}

criterion_group!(benches, benchmark_lm_fit);
criterion_main!(benches);

