    // In inference/src/lib.rs
    use statrs::distribution::{ContinuousCDF, F, StudentsT};

    // ...

    fn t_cdf(t: f64, df: i32) -> f64 {
        if df <= 0 {
            return 0.5; // Or handle as an error
        }
        // Use the highly accurate implementation from statrs
        if let Ok(dist) = StudentsT::new(0.0, 1.0, df as f64) {
            dist.cdf(t)
        } else {
            // Fallback for invalid df, e.g. df=0
